class Solution:
    def maxDepthAfterSplit(self, seq: str) -> List[int]:
        answer = []
        open_count = 0
        for char in seq:
            if char == '(':
                open_count += 1
                answer.append(0)
            else:
                open_count -= 1
                answer.append(1)
        return answer
